 21→const extractPlainText = (rawContent: string | null | undefined): string => {
 22→  if (!rawContent) {
 23→    return '';
 24→  }
 25→
 26→  try {
 27→    const parsed = JSON.parse(rawContent) as {
 28→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
 29→    };
 30→
 31→    const parts: string[] = [];
 32→    parsed.root?.children?.forEach(node => {
 33→      node.children?.forEach(child => {
 34→        if (child.text) {
 35→          parts.push(child.text);
 36→        }
 37→      });
 38→    });
 39→
 40→    return parts.join(' ').replace(/\s+/g, ' ').trim();
 41→  } catch {
 42→    return rawContent.replace(/\s+/g, ' ').trim();
 43→  }
 44→};
 45→
 46→const getNextCursor = (page: CursorPage<JournalItem>): string | undefined => {
 47→  if (page.nextCursor) {
 48→    return page.nextCursor;
 49→  }
 50→
 51→  if (page.hasMore && page.data.length > 0) {
 52→    return page.data[page.data.length - 1]?.created_at ?? undefined;
 53→  }
 54→
 55→  if (page.data.length >= PAGE_SIZE) {
 56→    return page.data[page.data.length - 1]?.created_at ?? undefined;
 57→  }
 58→
 59→  return undefined;
 60→};
 61→
 62→const normalizeCount = (value: unknown): number => {
 63→  const parsed = Number(value);
 64→  if (!Number.isFinite(parsed) || parsed < 0) {
 65→    return 0;
 66→  }
 67→  return parsed;
 68→};
 69→
 70→const resolveCount = (
 71→  aggregate: Array<{count?: number}> | undefined,
 72→  fallback?: number,
 73→): number => {
 74→  if (Array.isArray(aggregate) && aggregate.length > 0) {
 75→    return normalizeCount(aggregate[0]?.count);
 76→  }
 77→  return normalizeCount(fallback);
 78→};
