 21→
 22→const authHeaders = (token?: string): Record<string, string> => {
 23→  if (!token) {
 24→    return {};
 25→  }
 26→  return {Authorization: `Bearer ${token}`};
 27→};
 28→
 29→export const socialApi = {
 30→  async likeJournal(
 31→    token: string,
 32→    payload: {
 33→      journalId: string;
 34→      receiverId?: string;
 35→      senderImageUrl?: string;
 36→      sendername?: string;
 37→      senderEmail?: string;
 38→    },
 39→  ): Promise<{message?: string}> {
 40→    return apiRequest<{message?: string}>('/like', {
 41→      method: 'POST',
 42→      headers: {
 43→        ...authHeaders(token),
 44→        'Content-Type': 'application/json',
 45→      },
 46→      body: JSON.stringify(payload),
 47→    });
 48→  },
 49→
 50→  async addComment(
 51→    token: string,
 52→    payload: {comments: string; postId: string; receiverId?: string},
 53→  ): Promise<{message?: string}> {
 54→    return apiRequest<{message?: string}>('/addComment', {
 55→      method: 'POST',
 56→      headers: {
 57→        ...authHeaders(token),
 58→        'Content-Type': 'application/json',
 59→      },
 60→      body: JSON.stringify(payload),
 61→    });
 62→  },
 63→
 64→  async getComments(
 65→    postId: string,
 66→    cursor: string | null = null,
 67→    limit = 20,
 68→  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
 69→    const params = new URLSearchParams();
 70→    params.set('postId', postId);
 71→    params.set('limit', String(limit));
 72→    if (cursor) {
 73→      params.set('before', cursor);
 74→    }
 75→
 76→    return apiRequest<{comments: JournalComment[]; hasMore?: boolean}>(
 77→      `/getComments?${params.toString()}`,
 78→      {method: 'GET'},
 79→    );
 80→  },
 81→
 82→  async toggleBookmark(
 83→    token: string,
 84→    payload: {journalId: string},
 85→  ): Promise<{message?: string}> {
 86→    return apiRequest<{message?: string}>('/addBoorkmark', {
 87→      method: 'POST',
 88→      headers: {
 89→        ...authHeaders(token),
 90→        'Content-Type': 'application/json',
 91→      },
 92→      body: JSON.stringify(payload),
 93→    });
 94→  },
 95→
 96→  async getBookmarks(
 97→    token: string,
 98→    userId: string,
 99→    cursor: string | null = null,
100→    limit = 10,
101→  ): Promise<CursorPage<JournalItem>> {
102→    const params = new URLSearchParams();
103→    params.set('userId', userId);
104→    params.set('limit', String(limit));
105→    if (cursor) {
106→      params.set('before', cursor);
