 1→type LexicalNode = {
 2→  type?: string;
 3→  text?: string;
 4→  children?: LexicalNode[];
 5→};
 6→
 7→export const stripHtml = (html: string): string => {
 8→  return html
 9→    .replace(/<[^>]*>/g, ' ')
10→    .replace(/&nbsp;/g, ' ')
11→    .replace(/\s+/g, ' ')
12→    .trim();
13→};
14→
15→export const toLexicalFromPlainText = (plainText: string): string => {
16→  const payload = {
17→    root: {
18→      children: [
19→        {
20→          type: 'paragraph',
21→          children: [
22→            {
23→              type: 'text',
24→              text: plainText,
25→              detail: 0,
26→              format: 0,
27→              mode: 'normal',
28→              style: '',
29→              version: 1,
30→            },
31→          ],
32→          direction: null,
33→          format: '',
34→          indent: 0,
35→          version: 1,
36→        },
37→      ],
38→      direction: null,
39→      format: '',
40→      indent: 0,
41→      type: 'root',
42→      version: 1,
43→    },
44→  };
45→
46→  return JSON.stringify(payload);
47→};
48→
49→const collectText = (node: LexicalNode | null | undefined, bag: string[]) => {
50→  if (!node) {
51→    return;
52→  }
53→
54→  if (node.type === 'text' && typeof node.text === 'string') {
55→    bag.push(node.text);
56→  }
57→
58→  if (Array.isArray(node.children)) {
59→    node.children.forEach(child => collectText(child, bag));
60→  }
61→};
62→
63→export const extractPlainTextFromLexical = (
64→  rawContent: string | object | null | undefined,
65→): string => {
66→  if (!rawContent) {
67→    return '';
68→  }
69→
70→  try {
71→    const parsed =
72→      typeof rawContent === 'string'
73→        ? (JSON.parse(rawContent) as {root?: LexicalNode})
74→        : (rawContent as {root?: LexicalNode});
75→
76→    const parts: string[] = [];
77→    collectText(parsed.root, parts);
78→    return parts.join(' ').replace(/\s+/g, ' ').trim();
79→  } catch {
80→    return typeof rawContent === 'string' ? rawContent : '';
81→  }
82→};
